def _extract_bearer_token(req):
    auth = req.headers.get("Authorization", "")
    if not auth:
        return None
    m = re.match(r"^\s*Bearer\s+(.+?)\s*$", auth, re.IGNORECASE)
    if not m:
        return None
    return m.group(1)


